class PostState(rx.State):
@rx.var
def post_id(self) -> str:
return self.router.page.params.get("id", "0")
def post_detail():
return rx.vstack(
rx.heading(f"文章ID：{PostState.post_id}"),
rx.text("动态路由参数示例")
app.add_page(
post_detail,
route="/posts/[id]",
on_load=PostState.load_post # 页面加载时触发
